import{_ as t,c as s,o,a1 as a}from"./chunks/framework.DDNAyvCW.js";const i="/assets/MCP.CttIsW7S.png",n="/assets/add-mcp-server.ZT8Oh_Ip.gif",r="/assets/toggle-tools.DUrVpNU1.gif",d="/assets/auto-approve.BVy5g89q.png",l="/assets/tools-resources.vyXpns-O.png",f=JSON.parse('{"title":"MCP Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp/usage/index.md","filePath":"docs/mcp/usage/index.md"}'),c={name:"docs/mcp/usage/index.md"};function p(h,e,u,m,g,k){return o(),s("div",null,e[0]||(e[0]=[a('<h1 id="mcp-usage-guide" tabindex="-1">MCP Usage Guide <a class="header-anchor" href="#mcp-usage-guide" aria-label="Permalink to &quot;MCP Usage Guide&quot;">​</a></h1><p>MCP (Model Context Protocol) lets you extend Chaterm&#39;s AI with external tools, knowledge bases, and APIs by connecting to MCP servers.</p><p><img src="'+i+'" alt=""></p><h2 id="your-first-mcp-server" tabindex="-1">Your First MCP Server <a class="header-anchor" href="#your-first-mcp-server" aria-label="Permalink to &quot;Your First MCP Server&quot;">​</a></h2><p>Get up and running in under five minutes.</p><ol><li>Open <strong>Settings</strong> in Chaterm.</li><li>Go to the <strong>Tools &amp; MCP</strong> tab and click <strong>Add Server</strong> — this opens the <code>mcp_setting.json</code> file.</li><li>Paste one of the JSON examples below into the editor.</li><li>Save the file. Chaterm will automatically connect to the server.</li></ol><p>After saving, the server&#39;s status badge changes from <em>connecting</em> to <em>connected</em> (or displays an error message), and its Tools and Resources are loaded automatically.</p><p><img src="'+n+`" alt=""></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Not sure which server to try first? The <strong>filesystem</strong> server (shown below) is a great starting point — it gives the AI read/write access to directories you choose.</p></div><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="stdio-server-local-command-line" tabindex="-1">STDIO server (local command-line) <a class="header-anchor" href="#stdio-server-local-command-line" aria-label="Permalink to &quot;STDIO server (local command-line)&quot;">​</a></h3><p>Use this type when the MCP server runs as a local process on your machine.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// MCP server using stdio transport</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;@modelcontextprotocol/server-filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;/Users/username/Desktop&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;/path/to/other/allowed/dir&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="stdio-configuration-fields" tabindex="-1">STDIO configuration fields <a class="header-anchor" href="#stdio-configuration-fields" aria-label="Permalink to &quot;STDIO configuration fields&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>type</code></td><td>No</td><td>Connection type, inferred as <code>stdio</code> when <code>command</code> is provided if omitted</td><td><code>&quot;stdio&quot;</code></td></tr><tr><td><code>command</code></td><td>Yes</td><td>Executable command to start. Can be written as a complete line (with parameters) or just executable name</td><td><code>&quot;npx&quot;</code>, <code>&quot;node&quot;</code>, <code>&quot;python&quot;</code></td></tr><tr><td><code>args</code></td><td>No</td><td>Array of arguments passed to the command; when <code>command</code> contains spaces and <code>args</code> is not provided, the system will automatically parse (supports quotes and escaping)</td><td><code>[&quot;-y&quot;, &quot;@modelcontextprotocol/server-filesystem&quot;]</code></td></tr><tr><td><code>cwd</code></td><td>No</td><td>Process working directory</td><td><code>&quot;/Users/you&quot;</code></td></tr><tr><td><code>env</code></td><td>No</td><td>Process environment variables (key-value pairs)</td><td><code>{&quot;API_KEY&quot;: &quot;xxx&quot;}</code></td></tr><tr><td><code>disabled</code></td><td>No</td><td>Whether to disable this server</td><td><code>true</code>/<code>false</code></td></tr><tr><td><code>timeout</code></td><td>No</td><td>Call timeout (seconds)</td><td><code>120</code>, <code>180</code></td></tr><tr><td><code>autoApprove</code></td><td>No</td><td>Auto-approve tool whitelist (by tool name)</td><td><code>[&quot;read_file&quot;]</code></td></tr></tbody></table><p>Notes:</p><ul><li><code>envFile</code> field is not supported; if you need to load variables from a file, handle it in the startup environment before writing to <code>env</code>.</li><li>Compatible fields: For backward compatibility, <code>url?</code>, <code>headers?</code> are also allowed in stdio configuration, but not recommended (will not switch connection type to http).</li></ul><h3 id="http-server-remote-service" tabindex="-1">HTTP server (remote service) <a class="header-anchor" href="#http-server-remote-service" aria-label="Permalink to &quot;HTTP server (remote service)&quot;">​</a></h3><p>Use this type when the MCP server is hosted remotely and exposes a Streamable HTTP endpoint.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;context7&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://mcp.context7.com/mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;headers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;CONTEXT7_API_KEY&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-api-key&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="http-configuration-fields" tabindex="-1">HTTP configuration fields <a class="header-anchor" href="#http-configuration-fields" aria-label="Permalink to &quot;HTTP configuration fields&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>type</code></td><td>No</td><td>Connection type, inferred as <code>http</code> when <code>url</code> is provided if omitted</td><td><code>&quot;http&quot;</code></td></tr><tr><td><code>url</code></td><td>Yes</td><td>Server address (supports streaming HTTP client)</td><td><code>&quot;https://your-mcp-host.example.com/&quot;</code></td></tr><tr><td><code>headers</code></td><td>No</td><td>Request headers (e.g., authentication, proxy related)</td><td><code>{&quot;Authorization&quot;: &quot;Bearer &lt;TOKEN&gt;&quot;}</code></td></tr><tr><td><code>disabled</code></td><td>No</td><td>Whether to disable this server</td><td><code>true</code>/<code>false</code></td></tr><tr><td><code>timeout</code></td><td>No</td><td>Call timeout (seconds)</td><td><code>120</code>, <code>180</code></td></tr><tr><td><code>autoApprove</code></td><td>No</td><td>Auto-approve tool whitelist (by tool name)</td><td><code>[&quot;search&quot;]</code></td></tr></tbody></table><p>Notes:</p><ul><li><code>url</code> must be a valid URL (strictly validated by schema).</li><li>Compatible fields: For backward compatibility, <code>command?</code>, <code>args?</code>, <code>env?</code> are also allowed in http configuration, only for old configuration migration scenarios; not recommended for long-term use.</li></ul><h3 id="common-fields" tabindex="-1">Common fields <a class="header-anchor" href="#common-fields" aria-label="Permalink to &quot;Common fields&quot;">​</a></h3><blockquote><p>Reference <code>schemas.ts</code> in the project:</p><ul><li>Common fields (supported by both types): <code>disabled?</code>, <code>timeout?</code> (seconds, default value see application), <code>autoApprove?</code> (string array).</li><li><code>type</code> is optional: Can be omitted when <code>command</code> (inferred as stdio) or <code>url</code> (inferred as http) is provided; recommended to explicitly fill for better readability.</li><li>Compatible fields: Legacy <code>transportType</code> is supported, the application will automatically convert it to <code>type</code>; not recommended to continue using in new configurations.</li></ul></blockquote><hr><h2 id="using-mcp-in-conversations" tabindex="-1">Using MCP in Conversations <a class="header-anchor" href="#using-mcp-in-conversations" aria-label="Permalink to &quot;Using MCP in Conversations&quot;">​</a></h2><h3 id="toggling-tools-on-and-off" tabindex="-1">Toggling tools on and off <a class="header-anchor" href="#toggling-tools-on-and-off" aria-label="Permalink to &quot;Toggling tools on and off&quot;">​</a></h3><p>Click a tool name in the <strong>Tools</strong> list to enable or disable it. Disabled tools are removed from the model context entirely, so the Agent cannot use them. Turning off unused tools is a simple way to save tokens.</p><p><img src="`+r+'" alt=""></p><h3 id="auto-approval" tabindex="-1">Auto-approval <a class="header-anchor" href="#auto-approval" aria-label="Permalink to &quot;Auto-approval&quot;">​</a></h3><p>After adding tool names to <code>autoApprove</code> in the configuration, matching tools skip the confirmation step and execute immediately. You can also add tools to the auto-approve list dynamically during a conversation.</p><p><img src="'+d+'" alt=""></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Only add tools you fully trust to <code>autoApprove</code>. Auto-approved tools bypass the confirmation dialog and execute without user review.</p></div><h3 id="viewing-parameters-and-resources" tabindex="-1">Viewing parameters and resources <a class="header-anchor" href="#viewing-parameters-and-resources" aria-label="Permalink to &quot;Viewing parameters and resources&quot;">​</a></h3><p>Expand a tool&#39;s <strong>PARAMETERS</strong> panel to see parameter names, whether they are required, and their descriptions.</p><p>In the <strong>Resources</strong> tab you can view resource names, descriptions, and URIs; supported entry points can read resources directly.</p><p><img src="'+l+'" alt=""></p><hr><h2 id="development-tips" tabindex="-1">Development Tips <a class="header-anchor" href="#development-tips" aria-label="Permalink to &quot;Development Tips&quot;">​</a></h2><h3 id="file-change-auto-restart" tabindex="-1">File-change auto-restart <a class="header-anchor" href="#file-change-auto-restart" aria-label="Permalink to &quot;File-change auto-restart&quot;">​</a></h3><p>If you run a local MCP server from build artifacts (e.g., <code>build/index.js</code>), Chaterm detects changes to that file and automatically restarts the corresponding stdio server. This speeds up your development cycle significantly.</p><p>If auto-restart does not trigger, you can manually reconnect by toggling the server <strong>Disable then Enable</strong>.</p><hr><h2 id="where-to-find-mcp-servers" tabindex="-1">Where to Find MCP Servers <a class="header-anchor" href="#where-to-find-mcp-servers" aria-label="Permalink to &quot;Where to Find MCP Servers&quot;">​</a></h2><ul><li><strong>GitHub repositories</strong>: <ul><li><a href="https://github.com/modelcontextprotocol/servers" target="_blank" rel="noreferrer">modelcontextprotocol/servers</a></li><li><a href="https://github.com/punkpeye/awesome-mcp-servers" target="_blank" rel="noreferrer">punkpeye/awesome-mcp-servers</a></li></ul></li><li><strong>Online MCP directories</strong>: <ul><li><a href="https://mcpservers.org/" target="_blank" rel="noreferrer">mcpservers.org</a></li><li><a href="https://mcp.so/" target="_blank" rel="noreferrer">mcp.so</a></li><li><a href="https://glama.ai/mcp/servers" target="_blank" rel="noreferrer">glama.ai/mcp/servers</a></li></ul></li><li><strong>PulseMCP</strong>: <a href="https://www.pulsemcp.com/" target="_blank" rel="noreferrer">www.pulsemcp.com</a></li></ul><hr><h2 id="security-and-performance-recommendations" tabindex="-1">Security and Performance Recommendations <a class="header-anchor" href="#security-and-performance-recommendations" aria-label="Permalink to &quot;Security and Performance Recommendations&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Security checklist</p><ul><li>Only add trusted tools to <code>autoApprove</code>.</li><li>Be cautious when injecting credentials in <code>env</code> or <code>headers</code> — avoid sharing config files that contain secrets.</li><li>Follow the principle of least privilege: only expose the directories, networks, and APIs that are actually needed.</li></ul></div><ul><li><strong>Performance</strong>: For typical networks, set <code>timeout</code> to 120 - 180 seconds. For remote services, prefer nearby endpoints and make sure your proxy does not interrupt streaming connections.</li><li><strong>Maintainability</strong>: Use a consistent naming scheme and group related servers together. Back up your <code>mcp_setting.json</code> regularly.</li></ul><hr><h2 id="what-to-read-next" tabindex="-1">What to Read Next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to Read Next&quot;">​</a></h2><ul><li>Running into connection or call issues? See <a href="./../troubleshooting/">MCP Troubleshooting &amp; Best Practices</a>.</li></ul>',55)]))}const v=t(c,[["render",p]]);export{f as __pageData,v as default};
